import{_ as a,c as e,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"多言語サポート: 日英自動切り替え | opencode-mystatus","description":"opencode-mystatusの多言語サポートを理解します。言語検出原理（Intl APIと環境変数）と出力言語の切り替え方法を学びます。","frontmatter":{"title":"多言語サポート: 日英自動切り替え | opencode-mystatus","sidebarTitle":"多言語サポート","subtitle":"多言語サポート：日本語と英語の自動切り替え","description":"opencode-mystatusの多言語サポートを理解します。言語検出原理（Intl APIと環境変数）と出力言語の切り替え方法を学びます。","tags":["i18n","internationalization","language-detection","multi-language"],"prerequisite":["start-quick-start"],"order":3},"headers":[],"relativePath":"ja/vbgate/opencode-mystatus/advanced/i18n-setup/index.md","filePath":"ja/vbgate/opencode-mystatus/advanced/i18n-setup/index.md"}'),o={name:"ja/vbgate/opencode-mystatus/advanced/i18n-setup/index.md"};function n(l,t,d,r,h,c){return s(),e("div",null,[...t[0]||(t[0]=[i('<h1 id="多言語サポート-日本語と英語の自動切り替え" tabindex="-1">多言語サポート：日本語と英語の自動切り替え <a class="header-anchor" href="#多言語サポート-日本語と英語の自動切り替え" aria-label="Permalink to &quot;多言語サポート：日本語と英語の自動切り替え&quot;">​</a></h1><h2 id="学習後のスキル" tabindex="-1">学習後のスキル <a class="header-anchor" href="#学習後のスキル" aria-label="Permalink to &quot;学習後のスキル&quot;">​</a></h2><ul><li>mystatusが自動的にシステム言語を検出する方法を理解</li><li>出力言語を変更する方法を知る</li><li>言語検出の優先順位とフォールバックメカニズムを把握</li></ul><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><p><strong>多言語サポート</strong>はシステム言語環境に基づいて自動的に日本語または英語の出力を選択し、手動での設定は不要です。検出優先順位は：Intl API → 環境変数 → デフォルト英語。</p><p><strong>検出優先順位</strong>（高い順）：</p><ol><li><strong>Intl API</strong>（推奨）→ <code>Intl.DateTimeFormat().resolvedOptions().locale</code></li><li><strong>環境変数</strong>（フォールバック）→ <code>LANG</code>、<code>LC_ALL</code>、<code>LANGUAGE</code></li><li><strong>デフォルト英語</strong>（デフォルト）→ <code>&quot;en&quot;</code></li></ol><p><strong>サポートされる言語</strong>：</p><table tabindex="0"><thead><tr><th>言語</th><th>コード</th><th>検出条件</th></tr></thead><tbody><tr><td>日本語</td><td><code>ja</code></td><td>localeが <code>ja</code> で始まる（<code>ja-JP</code> など）</td></tr><tr><td>英語</td><td><code>en</code></td><td>その他の場合</td></tr></tbody></table><h2 id="実践" tabindex="-1">実践 <a class="header-anchor" href="#実践" aria-label="Permalink to &quot;実践&quot;">​</a></h2><h3 id="ステップ1-現在のシステム言語を確認" tabindex="-1">ステップ1：現在のシステム言語を確認 <a class="header-anchor" href="#ステップ1-現在のシステム言語を確認" aria-label="Permalink to &quot;ステップ1：現在のシステム言語を確認&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $LANG</span></span></code></pre></div><p><strong>期待される結果</strong>：</p><ul><li>日本語システム：<code>ja_JP.UTF-8</code> など</li><li>英語システム：<code>en_US.UTF-8</code> など</li></ul><h3 id="ステップ2-言語検出をテスト" tabindex="-1">ステップ2：言語検出をテスト <a class="header-anchor" href="#ステップ2-言語検出をテスト" aria-label="Permalink to &quot;ステップ2：言語検出をテスト&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/mystatus</span></span></code></pre></div><p><strong>期待される結果</strong>：</p><ul><li>システム言語が日本語の場合 → 日本語出力</li><li>システム言語が英語の場合 → 英語出力</li></ul><h3 id="ステップ3-一時的にシステム言語を切り替え-テスト用" tabindex="-1">ステップ3：一時的にシステム言語を切り替え（テスト用） <a class="header-anchor" href="#ステップ3-一時的にシステム言語を切り替え-テスト用" aria-label="Permalink to &quot;ステップ3：一時的にシステム言語を切り替え（テスト用）&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">LANG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">en_US.UTF-8</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> /mystatus</span></span></code></pre></div><h2 id="まとめ" tabindex="-1">まとめ <a class="header-anchor" href="#まとめ" aria-label="Permalink to &quot;まとめ&quot;">​</a></h2><ul><li><strong>自動検出</strong>：mystatusは自動的にシステム言語を検出し、手動での設定は不要</li><li><strong>検出優先順位</strong>：Intl API → 環境変数 → デフォルト英語</li><li><strong>サポート言語</strong>：日本語（ja）と英語（en）</li><li><strong>言語切り替え</strong>：システム言語設定を変更し、OpenCodeを再起動</li></ul><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を展開</strong></summary><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>言語検出関数</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/i18n.ts#L24-L40" target="_blank" rel="noreferrer"><code>plugin/lib/i18n.ts</code></a></td><td>24-40</td></tr></tbody></table></details>',25)])])}const g=a(o,[["render",n]]);export{u as __pageData,g as default};
